60	    /// Parse an expression with precedence climbing (min_prec=0 for full expr).
61	    pub(crate) fn parse_expr(&mut self, min_prec: u8) -> Result<Expr, ParseError> {
62	        let mut lhs = self.parse_atom()?;
63	        loop {
64	            let Some((op, prec)) = self.tokens.get(self.pos).and_then(|t| match t.kind {
65	                TokenKind::Plus => Some((BinOpKind::Add, 1u8)),
66	                TokenKind::Minus => Some((BinOpKind::Sub, 1)),
67	                TokenKind::Star => Some((BinOpKind::Mul, 2)),
68	                TokenKind::Slash => Some((BinOpKind::Div, 2)),
69	                _ => None,
70	            }) else {
71	                break;
72	            };
73	            if prec < min_prec {
74	                break;
75	            }
76	            self.pos += 1;
77	            let rhs = self.parse_expr(prec + 1)?;
78	            let span = Span::new(lhs.span().start, rhs.span().end);
79	            lhs = Expr::BinOp {
80	                op,
81	                lhs: Box::new(lhs),
82	                rhs: Box::new(rhs),
83	                span,
84	            };
85	        }
86	        Ok(lhs)
