90	        let tok = &self.tokens[self.pos];
91	        match &tok.kind {
92	            TokenKind::Minus => {
93	                let start = tok.span;
94	                self.pos += 1;
95	                let operand = self.parse_atom()?;
96	                let span = Span::new(start.start, operand.span().end);
