101	            }
102	            TokenKind::IntLit(n) => {
103	                let e = Expr::IntLit(*n, tok.span);
104	                self.pos += 1;
105	                Ok(e)
106	            }
107	            TokenKind::FloatLit(f) => {
108	                let e = Expr::FloatLit(*f, tok.span);
109	                self.pos += 1;
110	                Ok(e)
111	            }
112	            TokenKind::StrLit(s) => {
113	                let e = Expr::StrLit(s.clone(), tok.span);
114	                self.pos += 1;
115	                Ok(e)
116	            }
117	            TokenKind::Ident(name) => {
118	                let name = name.clone();
119	                let start = tok.span;
120	                self.pos += 1;
121	                // Function call: ident '('
122	                if self.is(TokenKind::LParen) {
123	                    self.pos += 1; // skip '('
124	                    let mut args = Vec::new();
125	                    if !self.is(TokenKind::RParen) {
126	                        args.push(self.parse_expr(0)?);
127	                        while self.is(TokenKind::Comma) {
128	                            self.pos += 1;
129	                            args.push(self.parse_expr(0)?);
130	                        }
131	                    }
132	                    if !self.is(TokenKind::RParen) {
133	                        return Err(ParseError::UnclosedDelimiter {
134	                            open: "(".into(),
135	                            span: start,
136	                        });
137	                    }
138	                    let end = self.tokens[self.pos].span;
139	                    self.pos += 1;
140	                    Ok(Expr::FnCall {
141	                        name,
142	                        args,
143	                        span: Span::new(start.start, end.end),
144	                    })
145	                } else {
146	                    Ok(Expr::Ident(name, start))
147	                }
148	            }
149	            TokenKind::LBracket => self.parse_array_lit(),
150	            TokenKind::LParen => {
151	                let open = tok.span;
152	                self.pos += 1;
153	                let expr = self.parse_expr(0)?;
154	                if !self.is(TokenKind::RParen) {
155	                    return Err(ParseError::UnclosedDelimiter {
156	                        open: "(".into(),
157	                        span: open,
158	                    });
159	                }
160	                self.pos += 1;
161	                Ok(expr)
162	            }
163	            _ => Err(ParseError::UnexpectedToken {
164	                found: describe_kind(&tok.kind),
165	                span: tok.span,
166	            }),
167	        }
168	    }
