171	        let open_span = self.tokens[self.pos].span;
172	        self.pos += 1;
173	        let mut elems = Vec::new();
174	        if !self.is(TokenKind::RBracket) {
175	            elems.push(self.parse_expr(0)?);
176	            while self.is(TokenKind::Comma) {
177	                self.pos += 1;
178	                elems.push(self.parse_expr(0)?);
179	            }
180	        }
