1	//! Runtime value type for MLPL.
2	
3	use std::fmt;
4	
5	use mlpl_array::DenseArray;
6	
7	use crate::error::EvalError;
8	
9	/// A runtime value: either an array or a string.
10	#[derive(Clone, Debug, PartialEq)]
11	pub enum Value {
12	    /// A dense array (scalar, vector, matrix, ...).
13	    Array(DenseArray),
14	    /// A string (introduced for diagram type names, LLM prompts, etc.).
15	    Str(String),
16	}
17	
18	impl Value {
19	    /// Extract the inner array, returning an error if this is a string.
20	    pub fn into_array(self) -> Result<DenseArray, EvalError> {
21	        match self {
22	            Self::Array(a) => Ok(a),
23	            Self::Str(_) => Err(EvalError::ExpectedArray),
24	        }
25	    }
26	
27	    /// Borrow the inner array, returning an error if this is a string.
28	    pub fn as_array(&self) -> Result<&DenseArray, EvalError> {
29	        match self {
30	            Self::Array(a) => Ok(a),
31	            Self::Str(_) => Err(EvalError::ExpectedArray),
32	        }
33	    }
34	}
35	
36	impl From<DenseArray> for Value {
37	    fn from(a: DenseArray) -> Self {
38	        Self::Array(a)
39	    }
40	}
41	
42	impl From<String> for Value {
43	    fn from(s: String) -> Self {
44	        Self::Str(s)
45	    }
46	}
47	
48	impl fmt::Display for Value {
49	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
50	        match self {
51	            Self::Array(a) => write!(f, "{a}"),
52	            Self::Str(s) => write!(f, "{s}"),
53	        }
54	    }
55	}
